import{_ as e,o,c as a,a2 as r}from"./chunks/framework.C58al07P.js";const h=JSON.parse('{"title":"Ops & Resilience","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/ops-resilience.md","filePath":"en/guide/ops-resilience.md"}'),i={name:"en/guide/ops-resilience.md"};function s(l,t,n,d,c,g){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="ops-resilience" tabindex="-1">Ops &amp; Resilience <a class="header-anchor" href="#ops-resilience" aria-label="Permalink to &quot;Ops &amp; Resilience&quot;">​</a></h1><p>Nid provides operations and resilience tools to manage storage, archive retention, Gmail API quota tracking, and mail import/export.</p><hr><h2 id="accessing-the-page" tabindex="-1">Accessing the Page <a class="header-anchor" href="#accessing-the-page" aria-label="Permalink to &quot;Accessing the Page&quot;">​</a></h2><p>In the sidebar, open the <strong>System</strong> group and click <strong>Ops &amp; Resilience</strong>.</p><p>The page is organized into 4 tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Feature</th></tr></thead><tbody><tr><td><strong>S3 Storage</strong></td><td>Remote storage configuration (S3, MinIO, Backblaze B2)</td></tr><tr><td><strong>Retention</strong></td><td>Automatic deletion policies for old archives</td></tr><tr><td><strong>API Quota</strong></td><td>Real-time tracking of Gmail API quota usage</td></tr><tr><td><strong>Import / Export</strong></td><td>Mbox and IMAP import, mbox export</td></tr></tbody></table><hr><h2 id="remote-storage-s3-minio" tabindex="-1">Remote Storage (S3 / MinIO) <a class="header-anchor" href="#remote-storage-s3-minio" aria-label="Permalink to &quot;Remote Storage (S3 / MinIO)&quot;">​</a></h2><p>By default, Nid stores EML archives on the local file system (NAS). You can configure S3-compatible storage to:</p><ul><li><strong>Geo-replicate</strong> your archives to a remote cloud</li><li>Use services such as <strong>AWS S3</strong>, <strong>MinIO</strong>, <strong>Backblaze B2</strong>, <strong>Wasabi</strong>, etc.</li><li>Separate storage from the application</li></ul><h3 id="configure-s3-storage" tabindex="-1">Configure S3 Storage <a class="header-anchor" href="#configure-s3-storage" aria-label="Permalink to &quot;Configure S3 Storage&quot;">​</a></h3><ol><li>In the <strong>S3 Storage</strong> tab, select the <strong>S3-compatible</strong> type</li><li>Fill in the connection details: <ul><li><strong>Endpoint</strong>: URL of your S3 server (e.g., <code>https://s3.amazonaws.com</code> or <code>https://minio.local:9000</code>)</li><li><strong>Region</strong>: S3 region (e.g., <code>us-east-1</code>, <code>eu-west-1</code>)</li><li><strong>Bucket</strong>: storage bucket name</li><li><strong>Access Key ID</strong> and <strong>Secret Access Key</strong>: access credentials</li><li><strong>Path-style</strong>: enable for MinIO (disable for AWS S3)</li></ul></li><li>Click <strong>Test Connection</strong> to verify that the credentials are correct</li><li>Click <strong>Save</strong></li></ol><blockquote><p>📸 <em>Suggested screenshot: S3 configuration form with endpoint, region, bucket fields and test/save buttons</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Global vs. per-user configuration</p><p>S3 storage can be configured in two ways:</p><ul><li><strong>Globally</strong> via environment variables (<code>S3_ENDPOINT</code>, <code>S3_ACCESS_KEY_ID</code>, etc.) — all users share the same storage</li><li><strong>Per user</strong> via the interface — each user can configure their own S3 storage</li></ul><p>Per-user configuration takes priority over the global configuration.</p></div><div class="info custom-block"><p class="custom-block-title">MinIO</p><p>To use MinIO (self-hosted), enable <strong>Path-style</strong> and point the endpoint to your MinIO instance (e.g., <code>http://minio:9000</code>).</p></div><h3 id="revert-to-local-storage" tabindex="-1">Revert to Local Storage <a class="header-anchor" href="#revert-to-local-storage" aria-label="Permalink to &quot;Revert to Local Storage&quot;">​</a></h3><p>Select the <strong>Local (NAS / disk)</strong> type and save.</p><hr><h2 id="retention-policies" tabindex="-1">Retention Policies <a class="header-anchor" href="#retention-policies" aria-label="Permalink to &quot;Retention Policies&quot;">​</a></h2><p>Retention policies automatically delete archives older than a configurable duration. This allows you to:</p><ul><li>Free up disk space</li><li>Comply with data retention policies</li><li>Automatically clean up old archives</li></ul><h3 id="create-a-policy" tabindex="-1">Create a Policy <a class="header-anchor" href="#create-a-policy" aria-label="Permalink to &quot;Create a Policy&quot;">​</a></h3><ol><li>In the <strong>Retention</strong> tab, click <strong>New Policy</strong></li><li>Fill in: <ul><li><strong>Name</strong>: descriptive name (e.g., &quot;Archives &gt; 2 years&quot;)</li><li><strong>Account</strong>: optional — to target a specific Gmail account, or all</li><li><strong>Label</strong>: optional — to target only emails with a particular label</li><li><strong>Retention days</strong>: maximum duration in days (e.g., 365 for 1 year, 730 for 2 years)</li></ul></li><li>Click <strong>Create</strong></li></ol><blockquote><p>📸 <em>Suggested screenshot: retention policy creation form</em></p></blockquote><h3 id="manage-policies" tabindex="-1">Manage Policies <a class="header-anchor" href="#manage-policies" aria-label="Permalink to &quot;Manage Policies&quot;">​</a></h3><ul><li><strong>Enable / Disable</strong>: use the switch to enable or disable a policy without deleting it</li><li><strong>Delete</strong>: permanently deletes the policy</li><li><strong>Run Now</strong>: manually triggers the application of all active policies</li></ul><p>The table displays for each policy:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>Policy name</td></tr><tr><td>Account</td><td>Targeted Gmail account (or &quot;All&quot;)</td></tr><tr><td>Label</td><td>Targeted Gmail label (or &quot;—&quot;)</td></tr><tr><td>Max Duration</td><td>Maximum age of archives</td></tr><tr><td>Deleted</td><td>Total number of archives deleted since creation</td></tr><tr><td>Last Run</td><td>Date of the last application</td></tr><tr><td>Active</td><td>Policy status</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Irreversible Deletion</p><p>Archives deleted by a retention policy are permanently erased (EML file + database entry). This action is irreversible.</p></div><hr><h2 id="gmail-api-quota-dashboard" tabindex="-1">Gmail API Quota Dashboard <a class="header-anchor" href="#gmail-api-quota-dashboard" aria-label="Permalink to &quot;Gmail API Quota Dashboard&quot;">​</a></h2><p>Google imposes a quota of <strong>250 units per user per second</strong> on the Gmail API. Each call consumes a variable number of units (e.g., <code>messages.get</code> = 5 units, <code>messages.send</code> = 100 units).</p><p>The quota dashboard allows you to:</p><ul><li><strong>Monitor</strong> your usage in real time</li><li><strong>Identify</strong> the most resource-consuming endpoints</li><li><strong>Anticipate</strong> quota overruns</li></ul><h3 id="reading-the-dashboard" tabindex="-1">Reading the Dashboard <a class="header-anchor" href="#reading-the-dashboard" aria-label="Permalink to &quot;Reading the Dashboard&quot;">​</a></h3><p>The <strong>API Quota</strong> tab displays:</p><table tabindex="0"><thead><tr><th>Block</th><th>Description</th></tr></thead><tbody><tr><td><strong>Last minute</strong></td><td>Units consumed + percentage of the limit (colored progress bar)</td></tr><tr><td><strong>Last hour</strong></td><td>Total units and requests over the past hour</td></tr><tr><td><strong>Last 24 hours</strong></td><td>Total units and requests over the past day</td></tr><tr><td><strong>Top endpoints</strong></td><td>Ranking of the most resource-consuming endpoints (24h)</td></tr><tr><td><strong>Hourly history</strong></td><td>Detailed hour-by-hour table (24h)</td></tr></tbody></table><blockquote><p>📸 <em>Suggested screenshot: quota dashboard with the 3 statistics at the top, the endpoints table in the middle, and the hourly history at the bottom</em></p></blockquote><div class="info custom-block"><p class="custom-block-title">Automatic Refresh</p><p>Quota data is automatically refreshed <strong>every 30 seconds</strong>.</p></div><h3 id="gmail-api-endpoint-costs" tabindex="-1">Gmail API Endpoint Costs <a class="header-anchor" href="#gmail-api-endpoint-costs" aria-label="Permalink to &quot;Gmail API Endpoint Costs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Units</th></tr></thead><tbody><tr><td><code>messages.get</code></td><td>5</td></tr><tr><td><code>messages.list</code></td><td>5</td></tr><tr><td><code>messages.send</code></td><td>100</td></tr><tr><td><code>messages.modify</code></td><td>5</td></tr><tr><td><code>messages.trash</code></td><td>5</td></tr><tr><td><code>messages.delete</code></td><td>10</td></tr><tr><td><code>messages.batchModify</code></td><td>50</td></tr><tr><td><code>messages.batchDelete</code></td><td>50</td></tr><tr><td><code>labels.list</code> / <code>labels.get</code></td><td>1</td></tr></tbody></table><hr><h2 id="mail-import" tabindex="-1">Mail Import <a class="header-anchor" href="#mail-import" aria-label="Permalink to &quot;Mail Import&quot;">​</a></h2><p>Nid lets you import emails from external sources into your archives.</p><h3 id="mbox-import" tabindex="-1">Mbox Import <a class="header-anchor" href="#mbox-import" aria-label="Permalink to &quot;Mbox Import&quot;">​</a></h3><p>The <strong>mbox</strong> format is a standard used by Google Takeout, Thunderbird, Apple Mail, and other email clients. It groups multiple emails into a single file.</p><ol><li>In the <strong>Import / Export</strong> tab, <strong>Mbox Import</strong> section, drop your <code>.mbox</code> file</li><li>An import job is created — track its progress on the <strong>Jobs</strong> page</li><li>Each email from the mbox file is converted to an individual EML and added to your archives</li></ol><p>The process:</p><ul><li>Parses each message from the mbox file</li><li>Extracts metadata (subject, sender, date, attachments)</li><li>Checks for duplicates (skips if the Message-ID already exists)</li><li>Stores the EML file + attachments separately</li><li>Indexes the email in PostgreSQL (full-text search)</li></ul><blockquote><p>📸 <em>Suggested screenshot: drag &amp; drop zone for the mbox file</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Google Takeout</p><p>To export your emails from Gmail:</p><ol><li>Go to <a href="https://takeout.google.com" target="_blank" rel="noreferrer">takeout.google.com</a></li><li>Select only <strong>Gmail</strong></li><li>Choose the <strong>mbox</strong> format</li><li>Download the archive and import the <code>.mbox</code> file into Nid</li></ol></div><h3 id="imap-import" tabindex="-1">IMAP Import <a class="header-anchor" href="#imap-import" aria-label="Permalink to &quot;IMAP Import&quot;">​</a></h3><p>Import emails directly from an IMAP server (Outlook, ProtonMail, Yahoo, etc.):</p><ol><li>In the <strong>IMAP Import</strong> section, fill in: <ul><li><strong>IMAP Server</strong>: server address (e.g., <code>imap.outlook.com</code>)</li><li><strong>Port</strong>: server port (default: 993)</li><li><strong>Username</strong>: your email login</li><li><strong>Password</strong>: your password or app-specific password</li><li><strong>Folder</strong>: IMAP folder to import (default: <code>INBOX</code>)</li><li><strong>Max messages</strong>: optional — limit the number of imported emails</li><li><strong>Secure connection</strong>: TLS enabled by default</li></ul></li><li>Click <strong>Start Import</strong></li><li>A job is created — track its progress on the <strong>Jobs</strong> page</li></ol><blockquote><p>📸 <em>Suggested screenshot: IMAP import form with server, port, username, and password fields</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">App-specific Password</p><p>Many providers (Google, Outlook, Yahoo) require a specific <strong>app password</strong> rather than your regular password. Check your email provider&#39;s documentation.</p></div><div class="info custom-block"><p class="custom-block-title">Common IMAP Servers</p><table tabindex="0"><thead><tr><th>Provider</th><th>Server</th><th>Port</th></tr></thead><tbody><tr><td>Outlook / Hotmail</td><td><code>imap-mail.outlook.com</code></td><td>993</td></tr><tr><td>Yahoo</td><td><code>imap.mail.yahoo.com</code></td><td>993</td></tr><tr><td>ProtonMail (Bridge)</td><td><code>127.0.0.1</code></td><td>1143</td></tr><tr><td>OVH</td><td><code>ssl0.ovh.net</code></td><td>993</td></tr><tr><td>Free</td><td><code>imap.free.fr</code></td><td>993</td></tr></tbody></table></div><hr><h2 id="mbox-export" tabindex="-1">Mbox Export <a class="header-anchor" href="#mbox-export" aria-label="Permalink to &quot;Mbox Export&quot;">​</a></h2><p>Export your archives in mbox format, compatible with most email clients:</p><ol><li>In the <strong>Mbox Export</strong> section, click <strong>Export as .mbox</strong></li><li>The file is generated and downloaded automatically</li></ol><p>The mbox file contains all your archived emails for the selected account, in standard RFC 4155 format.</p><div class="tip custom-block"><p class="custom-block-title">Re-importing</p><p>The exported mbox file can be imported into Thunderbird, Apple Mail, or any other compatible application. This is a good way to back up your archives in a universal format.</p></div>',64)])])}const m=e(i,[["render",s]]);export{h as __pageData,m as default};
